404 /// Calculate Start and End points of memory access using
405 /// getStartAndEndForAccess.
406 void RuntimePointerChecking::insert(Loop *Lp, Value *Ptr, const SCEV *PtrExpr,
407                                     Type *AccessTy, bool WritePtr,
408                                     unsigned DepSetId, unsigned ASId,
409                                     PredicatedScalarEvolution &PSE,
410                                     bool NeedsFreeze) {
411   const SCEV *SymbolicMaxBTC = PSE.getSymbolicMaxBackedgeTakenCount();
412   const SCEV *BTC = PSE.getBackedgeTakenCount();
413   const auto &[ScStart, ScEnd] = getStartAndEndForAccess(
414       Lp, PtrExpr, AccessTy, BTC, SymbolicMaxBTC, PSE.getSE(),
415       &DC.getPointerBounds(), DC.getDT(), DC.getAC(), LoopGuards);
416   assert(!isa<SCEVCouldNotCompute>(ScStart) &&
417          !isa<SCEVCouldNotCompute>(ScEnd) &&
418          "must be able to compute both start and end expressions");
419   Pointers.emplace_back(Ptr, ScStart, ScEnd, WritePtr, DepSetId, ASId, PtrExpr,
420                         NeedsFreeze);
421 }
